-- Secret key for HMAC signing - in production, load from environment/config
local SECRET_KEY = os.getenv("SESSION_SECRET") or "change-this-to-a-strong-random-secret-key"

local function hmac_sign(data)
    local hmac = require "resty.hmac"
    local h = hmac:new(SECRET_KEY, hmac.ALGOS.SHA256)
    if not h then
        return nil, "failed to create hmac instance"
    end
    local ok = h:update(data)
    if not ok then
        return nil, "failed to update hmac"
    end
    local digest = h:final()
    return ngx.encode_base64(digest)
end

local function hmac_verify(data, signature)
    local expected_sig, err = hmac_sign(data)
    if not expected_sig then
        return false, err
    end
    return expected_sig == signature
end

-- Serialize session data to a signed cookie value
function _M.serialize(session_data)
    if type(session_data) ~= "table" then
        return nil, "session_data must be a table"
    end

    local json_str, err = cjson.encode(session_data)
    if not json_str then
        return nil, "failed to encode session data: " .. (err or "unknown error")
    end

    local encoded_data = ngx.encode_base64(json_str)

    local signature, sign_err = hmac_sign(encoded_data)
    if not signature then
        return nil, "failed to sign session data: " .. (sign_err or "unknown error")
    end

    -- Format: base64(json_data).signature
    return encoded_data .. "." .. signature
end

-- Deserialize and verify session data from a signed cookie value
function _M.deserialize(cookie_value)
    if not cookie_value or type(cookie_value) ~= "string" then
        return nil, "invalid cookie value"
