    local dot_pos = cookie_value:find(".", 1, true)
    if not dot_pos then
        return nil, "malformed session cookie: missing signature"
    end

    local encoded_data = cookie_value:sub(1, dot_pos - 1)
    local signature = cookie_value:sub(dot_pos + 1)

    if not encoded_data or encoded_data == "" then
        return nil, "empty session data"
    end

    if not signature or signature == "" then
        return nil, "empty signature"
    end

    -- Verify HMAC signature to prevent tampering
    local valid, verify_err = hmac_verify(encoded_data, signature)
    if not valid then
